mapper.select:
SELECT A.CONT_NUM , A.CONT_CNT , A.BUYER_CD , A.BUYER_NM , A.PR_BUYER_CD , A.PR_BUYER_NM , A.PR_DEPT_CD , A.PR_DEPT_NM ,GETBUYERDEPTNAME(A.GATE_CD, A.PR_BUYER_CD, A.PR_DEPT_CD, #{ses.langCd}) AS PR_BUYER_DEPT_NM , A.CONT_USER_ID , A.CONTRACT_NM , A.CONT_DESC , A.PROGRESS_CD , A.VENDOR_CD , A.CONT_TYPE , A.CONT_REQ_CD , A.AUTO_RENEW_FLAG , A.BUNDLE_NUM , A.SIGN_STATUS ,(A.CONT_DATE, 'YYYYMMDD') AS CONT_DATE ,(A.ORIGIN_CONT_START_DATE, 'YYYYMMDD') AS ORIGIN_CONT_START_DATE ,(A.CONT_START_DATE, 'YYYYMMDD') AS CONT_START_DATE ,(A.CONT_END_DATE, 'YYYYMMDD') AS CONT_END_DATE , A.CUR , A.CONT_AMT , A.VAT_TYPE ,(A.SEND_DATE, 'YYYY-MM-DD HH24:MI') AS SEND_DATE ,(A.CONT_CLOSE_DATE, 'YYYYMMDD') AS CONT_CLOSE_DATE , A.CONT_CLOSE_RMK , (SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = A.GATE_CD AND UUID = A.ATT_FILE_NUM AND DEL_FLAG = '0') AS ATT_FILE_CNT , A.ATT_FILE_NUM , (SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = A.GATE_CD AND UUID = A.VENDOR_ATT_FILE_NUM AND DEL_FLAG = '0') AS VENDOR_ATT_FILE_CNT , A.VENDOR_ATT_FILE_NUM , (SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = A.GATE_CD AND UUID = A.STAMP_ATT_FILE_NUM AND DEL_FLAG = '0') AS STAMP_ATT_FILE_CNT , A.STAMP_ATT_FILE_NUM , A.S_SIGN_DATE , A.S_SIGN_ID , A.S_SING_NM , A.B_SIGN_DATE , A.B_SIGN_ID , A.B_SING_NM , A.GUAR_CNT , A.DI_GUAR_CNT , A.ADV_GUAR_CNT , A.WARR_GUAR_CNT , A.PDF_ATT_FILE_NUM , A.S_SIGN_DATE AS SIGN_DATE , A.FINISH_FLAG FROM (SELECT CT.GATE_CD , CT.BUYER_CD , GETCUSTNAME(CT.GATE_CD, CT.BUYER_CD) AS BUYER_NM , CT.CONT_NUM , CT.CONT_CNT , CT.CONT_USER_ID , GETUSERNAME(CT.GATE_CD, CT.CONT_USER_ID, #{ses.langCd}) AS CONTRACT_NM , CT.CONT_DESC , CT.PROGRESS_CD -- M135 , CT.CONT_REQ_CD -- M134 , CASE WHEN CT.AUTO_RENEW_FLAG IS NULL THEN '0' ELSE CT.AUTO_RENEW_FLAG END AS AUTO_RENEW_FLAG -- M044 , CT.BUNDLE_NUM , CT.SIGN_STATUS -- M020 , CT.CONT_DATE , CT.ORIGIN_CONT_START_DATE , CT.CONT_START_DATE , CT.CONT_END_DATE , CT.CUR -- M023 , CT.VAT_TYPE -- M100 , CT.SEND_DATE , CT.CONT_CLOSE_DATE , ((CT.CONT_CLOSE_DATE, CT.CONT_END_DATE), 'YYYYMMDD') - (SYSDATE, 'YYYYMMDD') AS CONT_EXPIRE_DAY , CT.CONT_CLOSE_RMK , CT.ATT_FILE_NUM , CT.VENDOR_ATT_FILE_NUM , CT.STAMP_ATT_FILE_NUM , CT.SIGN_DATE , SS.PR_BUYER_CD , GETCUSTNAME(SS.GATE_CD, SS.PR_BUYER_CD) AS PR_BUYER_NM , SS.PR_DEPT_CD , GETDEPTNAME(SS.GATE_CD, SS.PR_BUYER_CD, SS.PR_DEPT_CD, #{ses.langCd}) AS PR_DEPT_NM , SS.VENDOR_CD , SS.CONT_AMT , ECCF.CONT_TYPE , (SS.B_SIGN_DATE, 'YYYY-MM-DD HH24:MI') AS B_SIGN_DATE , SS.B_SIGN_ID , GETUSERNAME(SS.GATE_CD, SS.B_SIGN_ID, #{ses.langCd}) AS B_SING_NM , (SS.S_SIGN_DATE, 'YYYY-MM-DD HH24:MI') AS S_SIGN_DATE , SS.S_SIGN_ID , GETUSERNAME(SS.GATE_CD, SS.S_SIGN_ID, #{ses.langCd}) AS S_SING_NM , CASE WHEN SS.GUAR_CNT = 0 THEN (CASE WHEN DENO_GUAR_CNT = 0 THEN NULL ELSE 0 END) ELSE SS.GUAR_CNT END AS GUAR_CNT , CASE WHEN SS.DI_GUAR_CNT = 0 THEN (CASE WHEN DENO_DI_GUAR_CNT = 0 THEN NULL ELSE 0 END) ELSE SS.DI_GUAR_CNT END AS DI_GUAR_CNT , CASE WHEN SS.ADV_GUAR_CNT = 0 THEN (CASE WHEN DENO_ADV_GUAR_CNT = 0 THEN NULL ELSE 0 END) ELSE SS.ADV_GUAR_CNT END AS ADV_GUAR_CNT , CASE WHEN SS.WARR_GUAR_CNT = 0 THEN (CASE WHEN DENO_WARR_GUAR_CNT = 0 THEN NULL ELSE 0 END) ELSE SS.WARR_GUAR_CNT END AS WARR_GUAR_CNT , SS.PDF_ATT_FILE_NUM , CASE WHEN SYSDATE > CT.CONT_END_DATE THEN '1' ELSE '0' END AS FINISH_FLAG FROM STOCECCT CT JOIN (SELECT ECCT.GATE_CD , ECCT.BUYER_CD , ECCT.CONT_NUM , ECCT.CONT_CNT , ECPC_M.PY_BUYER_CD AS PR_BUYER_CD , ECPC_M.PY_DEPT_CD AS PR_DEPT_CD , ECPC_M.VENDOR_CD AS VENDOR_CD , ECPC_M.PAY_AMT AS CONT_AMT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'CONT' AND ECPC.GUAR_PERCENT > 0 AND ECPC.GUAR_TYPE2 IS NOT NULL THEN 1 ELSE 0 END) AS GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'DIF' AND ECPC.GUAR_AMT > 0 AND ECPC.ATT_FILE_NUM IS NOT NULL THEN 1 ELSE 0 END) AS DI_GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'ADV' AND ECPC.GUAR_PERCENT > 0 AND ECPC.GUAR_TYPE2 IS NOT NULL THEN 1 ELSE 0 END) + SUM(CASE WHEN IVAP.GUAR_TYPE = 'ADV' AND IVAP.GUAR_PERCENT > 0 AND IVAP.GUAR_TYPE2 IS NOT NULL THEN 1 ELSE 0 END) AS ADV_GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'WARR' AND ECPC.GUAR_PERCENT > 0 AND ECPC.GUAR_TYPE2 IS NOT NULL THEN 1 ELSE 0 END) + SUM(CASE WHEN IVAP.GUAR_TYPE = 'WARR' AND IVAP.GUAR_PERCENT > 0 AND IVAP.GUAR_TYPE2 IS NOT NULL THEN 1 ELSE 0 END) AS WARR_GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'CONT' AND ECPC.GUAR_PERCENT > 0 THEN 1 ELSE 0 END) AS DENO_GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'DIF' AND ECPC.GUAR_AMT > 0 THEN 1 ELSE 0 END) AS DENO_DI_GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'ADV' AND ECPC.GUAR_PERCENT > 0 THEN 1 ELSE 0 END) AS DENO_ADV_GUAR_CNT , SUM(CASE WHEN ECPC.GUAR_TYPE = 'WARR' AND ECPC.GUAR_PERCENT > 0 THEN 1 ELSE 0 END) AS DENO_WARR_GUAR_CNT , ECSVB.SIGN_DATE AS B_SIGN_DATE , ECSVB.SIGN_ID AS B_SIGN_ID , ECSVS.SIGN_DATE AS S_SIGN_DATE , ECSVS.SIGN_ID AS S_SIGN_ID ,ECPC_M.PDF_ATT_FILE_NUM FROM STOCECCT ECCT JOIN STOCECPC ECPC_M ON (ECPC_M.GATE_CD = ECCT.GATE_CD AND ECPC_M.BUYER_CD = ECCT.BUYER_CD AND ECPC_M.CONT_NUM = ECCT.CONT_NUM AND ECPC_M.CONT_CNT = ECCT.CONT_CNT AND ECPC_M.PAY_CNT = '0' AND ECPC_M.DEL_FLAG = '0') LEFT OUTER JOIN STOCECPC ECPC ON (ECPC.GATE_CD = ECPC_M.GATE_CD AND ECPC.BUYER_CD = ECPC_M.BUYER_CD AND ECPC.CONT_NUM = ECPC_M.CONT_NUM AND ECPC.CONT_CNT = ECPC_M.CONT_CNT AND ECPC.PR_BUYER_CD = ECPC_M.PR_BUYER_CD AND ECPC.PR_DEPT_CD = ECPC_M.PR_DEPT_CD AND ECPC.VENDOR_CD = ECPC_M.VENDOR_CD AND ECPC.DEL_FLAG = '0') LEFT OUTER JOIN STOCIVAP IVAP ON (IVAP.GATE_CD = ECPC.GATE_CD AND IVAP.BUYER_CD = ECPC.BUYER_CD AND IVAP.CONT_NUM = ECPC.CONT_NUM AND IVAP.CONT_CNT = ECPC.CONT_CNT AND IVAP.PR_BUYER_CD = ECPC.PR_BUYER_CD AND IVAP.PR_DEPT_CD = ECPC.PR_DEPT_CD AND IVAP.VENDOR_CD = ECPC.VENDOR_CD AND IVAP.PAY_CNT = ECPC.PAY_CNT AND IVAP.PY_BUYER_CD = ECPC.PY_BUYER_CD AND IVAP.PY_DEPT_CD = ECPC.PY_DEPT_CD AND IVAP.DEL_FLAG = '0') LEFT OUTER JOIN STOCECSV ECSVB ON (ECSVB.GATE_CD = ECPC_M.GATE_CD AND ECSVB.BUYER_CD = ECPC_M.BUYER_CD AND ECSVB.CONT_NUM = ECPC_M.CONT_NUM AND ECSVB.CONT_CNT = ECPC_M.CONT_CNT AND ECSVB.VENDOR_CD = ECPC_M.VENDOR_CD AND ECSVB.SIGN_ID = (CASE WHEN ECCT.BUNDLE_NUM IS NULL THEN ECPC_M.SIGN_ID ELSE ECSVB.SIGN_ID END) AND ECSVB.USER_TYPE = 'B') LEFT OUTER JOIN STOCECSV ECSVS ON (ECSVS.GATE_CD = ECPC_M.GATE_CD AND ECSVS.BUYER_CD = ECPC_M.BUYER_CD AND ECSVS.CONT_NUM = ECPC_M.CONT_NUM AND ECSVS.CONT_CNT = ECPC_M.CONT_CNT AND ECSVS.VENDOR_CD = ECPC_M.VENDOR_CD AND ECSVS.USER_TYPE = 'S') WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.VENDOR_CD = #{ses.companyCd} AND (ECCT.PROGRESS_CD >= '4210' -- 협력회사 서명대기 OR ECCT.VENDOR_SEND_FLAG = '1') -- 협력사전송여부=Y(작성중인 계약서 협력사 전송여부) AND (ECCT.MANUAL_CONT_FLAG IS NULL OR ECCT.MANUAL_CONT_FLAG != '1') -- 수기계약제외(수기계약은 내부관리용) AND ECCT.DEL_FLAG = '0'
AND ECCT.CONT_DATE BETWEEN TO_DATE(#{REG_DATE_FROM} '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{REG_DATE_TO} '235959', 'YYYYMMDDHH24MISS')
AND (UPPER(ECCT.CONT_NUM) LIKE UPPER('%' #{CONT_DESC} '%') OR UPPER(ECCT.CONT_DESC) LIKE UPPER('%' #{CONT_DESC} '%') )
AND ECCT.CONT_REQ_CD = #{CONT_REQ_CD}
AND ECCT.PROGRESS_CD IN
#{item}
GROUP BY ECCT.GATE_CD, ECCT.BUYER_CD, ECCT.CONT_NUM, ECCT.CONT_CNT ,ECPC_M.PY_BUYER_CD, ECPC_M.PY_DEPT_CD, ECPC_M.VENDOR_CD, ECPC_M.PAY_AMT ,ECSVS.SIGN_DATE, ECSVS.SIGN_ID, ECSVB.SIGN_DATE, ECSVB.SIGN_ID ,ECPC_M.PDF_ATT_FILE_NUM ) SS ON (SS.GATE_CD = CT.GATE_CD AND SS.BUYER_CD = CT.BUYER_CD AND SS.CONT_NUM = CT.CONT_NUM AND SS.CONT_CNT = CT.CONT_CNT) JOIN STOCECRL ECRL ON (ECRL.GATE_CD = CT.GATE_CD AND ECRL.BUYER_CD = CT.BUYER_CD AND ECRL.CONT_NUM = CT.CONT_NUM AND ECRL.CONT_CNT = CT.CONT_CNT AND ECRL.FORM_SQ = '0' AND ECRL.DEL_FLAG = '0') JOIN STOCECCF ECCF ON (ECCF.GATE_CD = ECRL.GATE_CD AND ECCF.FORM_NUM = ECRL.FORM_NUM) WHERE 1 = 1 ) A WHERE 1 = 1
AND (UPPER(A.PR_BUYER_NM) LIKE '%' UPPER(#{PR_BUYER_DEPT_NM}) '%' OR UPPER(A.PR_DEPT_NM) LIKE '%' UPPER(#{PR_BUYER_DEPT_NM}) '%')
AND UPPER(A.CONTRACT_NM) LIKE '%' UPPER(#{USER_NM}) '%'
AND A.AUTO_RENEW_FLAG = #{AUTO_RENEW_FLAG}
AND A.FINISH_FLAG = #{CONT_END_FLAG}
ORDER BY A.CONT_NUM DESC , A.CONT_CNT DESC

