mapper.insert:
INSERT INTO STOCECSV (
	  GATE_CD
	, BUYER_CD
	, CONT_NUM
	, CONT_CNT
	, SIGN_ID
	, REG_DATE
	, REG_USER_ID
	, SIGN_DATE
	, SIGN_VALUE
	, VENDOR_CD
	, USER_TYPE
	, VID_RANDOM
) VALUES (
	  #{ses.gateCd}
	, #{BUYER_CD}
	, #{CONT_NUM}
	, #{CONT_CNT}
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{SIGN_VALUE}
	, #{VENDOR_CD}
	, #{ses.userType}
	, #{VID_RANDOM}
)

mapper.update:
INSERT INTO STOCECRJ (
	 GATE_CD
	,BUYER_CD
	,CONT_NUM
	,CONT_CNT
	,REJECT_SQ
	,REG_DATE
	,REG_USER_ID
	,REJECT_RMK
) VALUES (
	 #{ses.gateCd}
	,#{BUYER_CD}
	,#{CONT_NUM}
	,#{CONT_CNT}
	,(SELECT (MAX(REJECT_SQ)+1, '1')
	    FROM STOCECRJ
	   WHERE GATE_CD = #{ses.gateCd}
	     AND BUYER_CD = #{BUYER_CD}
	     AND CONT_NUM = #{CONT_NUM}
	     AND CONT_CNT = #{CONT_CNT})
	,SYSDATE
	,#{ses.userId}
	,#{REJECT_RMK}
)

UPDATE STOCECPC
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
     , GUAR_TYPE2 = #{GUAR_TYPE2}
	 , GUARANTEER = #{GUARANTEER}
	 , GUAR_NUM = #{GUAR_NUM}
	 , ATT_FILE_NUM = #{ATT_FILE_NUM}
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND PR_BUYER_CD = #{PR_BUYER_CD}
   AND PR_DEPT_CD = #{PR_DEPT_CD}
   AND VENDOR_CD = #{ses.companyCd}
   AND PAY_CNT = #{PAY_CNT}
   AND PY_BUYER_CD =  #{PY_BUYER_CD}
   AND PY_DEPT_CD = #{PY_DEPT_CD}

UPDATE STOCECPC
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
	 , ATT_FILE_NUM = #{ATT_FILE_NUM}
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND PR_BUYER_CD = #{PR_BUYER_CD}
   AND PR_DEPT_CD = #{PR_DEPT_CD}
   AND VENDOR_CD = #{ses.companyCd}
   AND PAY_CNT = #{PAY_CNT}
   AND PY_BUYER_CD =  #{PY_BUYER_CD}
   AND PY_DEPT_CD = #{PY_DEPT_CD}

UPDATE STOCECPC
   SET GUAR_TYPE2 = #{GUAR_TYPE2}
	 , GUARANTEER = #{GUARANTEER}
	 , ATT_FILE_NUM = #{ATT_FILE_NUM}
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND PR_BUYER_CD = #{PR_BUYER_CD}
   AND PR_DEPT_CD = #{PR_DEPT_CD}
   AND VENDOR_CD = #{VENDOR_CD}
   AND PAY_CNT = #{PAY_CNT}
   AND PY_BUYER_CD = #{PY_BUYER_CD}
   AND PY_DEPT_CD = #{PY_DEPT_CD}

		UPDATE STOCECPC
		   SET ATT_FILE_NUM = #{DI_ATT_FILE_NUM}
		 WHERE GATE_CD = #{ses.gateCd}
		   AND BUYER_CD = #{BUYER_CD}
    	   AND CONT_NUM = #{CONT_NUM}
    	   AND CONT_CNT = #{CONT_CNT}
    	   AND PR_BUYER_CD = #{PR_BUYER_CD}
    	   AND PR_DEPT_CD = #{PR_DEPT_CD}
    	   AND VENDOR_CD = #{VENDOR_CD}
    	   AND PAY_CNT = #{PAY_CNT}
    	   AND PY_BUYER_CD = #{PY_BUYER_CD}
    	   AND PY_DEPT_CD = #{PY_DEPT_CD}

mapper.select:
SELECT ECCT.CONT_NUM , ECCT.CONT_CNT , ECCT.CONT_DESC , ECCT.BUYER_CD , ECCT.PROGRESS_CD ,GETCOMCODE(ECCT.GATE_CD,'M135',ECCT.PROGRESS_CD,'0',#{ses.langCd}) AS PROGRESS_NM ,((SELECT (MAX(SIGN_DATE), 'YYYY-MM-DD HH24:MI') FROM STOCECSV WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND FORM_NUM = ECCF.FORM_NUM AND USER_TYPE = 'B'),'서명안됨') AS BUYER_SIGN_DATE ,((SELECT (SIGN_DATE, 'YYYY-MM-DD HH24:MI:SS') FROM STOCECSV WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND FORM_NUM = ECCF.FORM_NUM AND VENDOR_CD = ECCT.VENDOR_CD AND USER_TYPE = 'S'),'서명안됨') AS VENDOR_SIGN_DATE , VNGL.VENDOR_NM , VNGL.CEO_USER_NM AS VENDOR_CEO_NM , VNGL.HQ_ADDR_1 ' ' VNGL.HQ_ADDR_2 AS VENDOR_ADDR , OGCM.BUYER_NM , OGCM.CEO_USER_NM AS BUYER_CEO_NM , OGCM.ADDR AS BUYER_ADDR , ECRL.CONTRACT_TEXT_NUM , ECRL.CONTRACT_TEXT ,(SYSDATE, 'YYYY"년"MM"월"DD"일"') AS SIGN_DATE, -- 자동갱신전자서명일자 , ECAR.SIGN_USER_ID -- 자동갱신전자서명자 , ECAR.SIGN_TEXT_NUM -- 서명내용번호 FROM STOCECCT ECCT JOIN STOCECRL ECRL ON (ECCT.GATE_CD = ECRL.GATE_CD AND ECCT.BUYER_CD = ECRL.BUYER_CD AND ECCT.CONT_NUM = ECRL.CONT_NUM AND ECCT.CONT_CNT = ECRL.CONT_CNT AND ECRL.FORM_SQ = 0 -- 주서식 AND ECRL.DEL_FLAG = '0') JOIN STOCECCF ECCF ON (ECRL.GATE_CD = ECCF.GATE_CD AND ECRL.FORM_NUM = ECCF.FORM_NUM) LEFT OUTER JOIN STOCVNGL VNGL ON (ECCT.GATE_CD = VNGL.GATE_CD AND ECCT.VENDOR_CD = VNGL.VENDOR_CD) LEFT OUTER JOIN STOCOGCM OGCM ON (ECCT.GATE_CD = OGCM.GATE_CD AND ECCT.BUYER_CD = OGCM.BUYER_CD AND ECCT.BUYER_CD = OGCM.BUYER_CD) LEFT OUTER JOIN STOCECAR ECAR -- 자동갱신거절 ON (ECCT.GATE_CD = ECAR.GATE_CD AND ECCT.CONT_NUM = ECAR.CONT_NUM AND ECCT.CONT_CNT = ECAR.CONT_CNT) WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.CONT_NUM = #{CONT_NUM}
AND ECCT.CONT_CNT = #{CONT_CNT}
AND ECCT.CONT_CNT = (SELECT MAX(CONT_CNT) FROM STOCECCT WHERE GATE_CD = ECCT.GATE_CD AND CONT_NUM = ECCT.CONT_NUM AND PROGRESS_CD = '4300')
AND ECCT.DEL_FLAG = '0'

SELECT ECCT.CONT_NUM , ECCT.CONT_CNT , ECCT.PROGRESS_CD ,GETCOMCODE(ECCT.GATE_CD,'M135',ECCT.PROGRESS_CD,'0',#{ses.langCd}) AS PROGRESS_NM ,((SELECT (SIGN_DATE, 'YYYY-MM-DD HH24:MI:SS') FROM STOCECSV WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND FORM_NUM = ECCF.FORM_NUM AND SIGN_ID = ECCT.CONT_USER_ID),'서명안됨') AS BUYER_SIGN_DATE ,((SELECT (SIGN_DATE, 'YYYY-MM-DD HH24:MI:SS') FROM STOCECSV WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND FORM_NUM = ECCF.FORM_NUM AND ECCT.VENDOR_CD = (SELECT COMPANY_CD FROM STOCUSER WHERE GATE_CD = #{ses.gateCd} AND USER_ID = SIGN_ID)),'서명안됨') AS VENDOR_SIGN_DATE ,GETVENDORNAME(ECCT.GATE_CD, ECCT.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , (SELECT BUYER_NM FROM STOCOGCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD) AS BUYER_NM , ECRL.CONTRACT_TEXT_NUM , ECRL.CONTRACT_TEXT FROM STOCECCT ECCT JOIN STOCECRL ECRL ON (ECCT.GATE_CD = ECRL.GATE_CD AND ECCT.BUYER_CD = ECRL.BUYER_CD AND ECCT.CONT_NUM = ECRL.CONT_NUM AND ECCT.CONT_CNT = ECRL.CONT_CNT AND ECRL.FORM_SQ > 0 -- 부서식 AND ECRL.DEL_FLAG = '0') JOIN STOCECCF ECCF ON (ECRL.GATE_CD = ECCF.GATE_CD AND ECRL.FORM_NUM = ECCF.FORM_NUM) WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.CONT_NUM = #{CONT_NUM}
AND ECCT.CONT_CNT = #{CONT_CNT}
AND ECCT.CONT_CNT = (SELECT MAX(CONT_CNT) FROM STOCECCT WHERE GATE_CD = ECCT.GATE_CD AND CONT_NUM = ECCT.CONT_NUM AND PROGRESS_CD = '4300')
AND ECCT.DEL_FLAG = '0' ORDER BY ECRL.FORM_SQ

SELECT CASE WHEN SUM(GUAR_AMT) > 0 THEN 1 ELSE 0 END AS GUAR_FLAG
  FROM STOCECPC
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND CONT_NUM  = #{CONT_NUM}
   AND CONT_CNT  = #{CONT_CNT}
   AND VENDOR_CD = #{ses.companyCd}
   AND PAY_CNT   = '-1'

SELECT '004'||'001'||'XXXXXXXXXX'||' 00' head_docu_numb /* [필수] 문서번호 */ , #{HEAD_MESG_SEND}||'.'||TO_CHAR(SYSDATE,'YYYYMMDD')||TO_CHAR(SYSDATE,'HH24MISS')||'.12345.004'||'001'||'XXXXXXXXXX'||' 00' head_mang_numb /* [필수] 문서관리번호 */ ,'004'||'001'||'XXXXXXXXXX'||' 00' head_refr_numb /* [필수] 참조번호 */
