,B.VENDOR_PIC_USER_NM appl_chrg_name /* [필수] 담당자명 */ ,'계약부서' appl_dept_name /* [필수] 소속부서 */ ,B.VENDOR_PIC_USER_CELL_NUM appl_offc_phon /* [필수] 전화번호 */ ,B.VENDOR_PIC_USER_CELL_NUM appl_cell_phon /* [필수] 핸드폰번호 */ ,B.VENDOR_PIC_USER_EMAIL appl_send_mail /* [필수] 담당자 EMAIL */ ,null appl_home_post /* [선택] 자택 우편번호 */ ,null appl_home_addr /* [선택] 자택 주소 */ ,null appl_home_phon /* [선택] 자택 전화번호 */ ,null appl_user_iden /* [필수] 수신처ID */ ,null appl_user_type /* [필수] 수신처TYPE */ ,A.GUAR_REQ_NUM ,A.INSU_STATUS ,A.GUAR_NUM FROM ( SELECT GUAR_TYPE ,GUAR_QT ,GUAR_AMT ,BOND_BEGN_DATE ,PAY_AMT ,GUAR_PERCENT ,GATE_CD ,BUYER_CD ,CONT_NUM ,CONT_CNT ,PY_BUYER_CD ,PY_DEPT_CD ,( SELECT MAX(GUAR_REQ_NUM) FROM STOCECPC WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND CONT_NUM = A.CONT_NUM AND CONT_CNT = A.CONT_CNT AND PY_BUYER_CD = A.PY_BUYER_CD AND PY_DEPT_CD = A.PY_DEPT_CD AND PAY_CNT = A.PAY_CNT ) GUAR_REQ_NUM ,INSU_STATUS ,GUAR_NUM FROM STOCECPC A WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND CONT_NUM = #{CONT_NUM} AND CONT_CNT = #{CONT_CNT} AND PR_BUYER_CD = #{PR_BUYER_CD} AND PR_DEPT_CD = #{PR_DEPT_CD} AND VENDOR_CD = #{VENDOR_CD} AND PAY_CNT = #{PAY_CNT} AND PY_BUYER_CD = #{PY_BUYER_CD} AND PY_DEPT_CD = #{PY_DEPT_CD} UNION ALL--=================================================================================== SELECT GUAR_TYPE ,GUAR_QT ,GUAR_AMT ,BOND_BEGN_DATE ,AP_REQ_AMT AS PAY_AMT ,GUAR_PERCENT ,GATE_CD ,BUYER_CD ,CONT_NUM ,CONT_CNT ,PY_BUYER_CD ,PY_DEPT_CD ,( SELECT MAX(GUAR_REQ_NUM) FROM STOCIVAP WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND CONT_NUM = A.CONT_NUM --AND CONT_CNT = A.CONT_CNT --AND PY_BUYER_CD = A.PY_BUYER_CD --AND PY_DEPT_CD = A.PY_DEPT_CD ) GUAR_REQ_NUM ,INSU_STATUS ,GUAR_NUM FROM STOCIVAP A WHERE GATE_CD = #{ses.gateCd} AND AP_NUM = #{AP_NUM} ) A JOIN STOCECCT B ON A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.CONT_NUM = B.CONT_NUM AND A.CONT_CNT = B.CONT_CNT JOIN STOCCUST C ON A.GATE_CD = C.GATE_CD AND A.PY_BUYER_CD = C.CUST_CD JOIN STOCCVUR D ON B.GATE_CD = D.GATE_CD -- 구매사담당자 AND B.CONT_USER_ID = D.USER_ID JOIN STOCVNGL E ON B.GATE_CD = E.GATE_CD AND B.VENDOR_CD = E.VENDOR_CD LEFT OUTER JOIN ( -- 이전 계약 SELECT * FROM STOCECCT WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND CONT_NUM = #{CONT_NUM} AND CONT_CNT = #{CONT_CNT} - 1 UNION ALL SELECT * FROM STOCECCT WHERE (GATE_CD,BUYER_CD,CONT_NUM,CONT_CNT) IN ( SELECT GATE_CD,BUYER_CD,CONT_NUM,CONT_CNT - 1 FROM STOCIVAP WHERE GATE_CD = #{ses.gateCd} AND AP_NUM = #{AP_NUM} ) ) G ON 1 = 1 WHERE ROWNUM = 1

/* * 문서코드(문서명) - BIDINF(입찰정보통보서), CONINF(계약정보통보서), FLRINF(하자정보통보서), PREINF(선금정보통보서), PAYINF(지급정보통보서), LIVINF(생활안정통보서), SALINF(상품판매통보서) * 상품(보험종류)구분코드- 001:입찰, 002:계약, 003:하자, 004:선금, 005:상판(상품판매), 006:지급, 007:생활안정, 008:공사이행, 009:납세 */
SELECT 'XXXXXXXXXX'||B.CONT_CNT head_docu_numb /* 문서번호 */ ,'21'||'.'||TO_CHAR(SYSDATE,'YYYYMMDD')||TO_CHAR(SYSDATE,'HH24MISS')||'.'||'XXXXXXXXXX'||B.CONT_CNT head_mang_numb /* 문서관리번호 */ ,'XXXXXXXXXX'||B.CONT_CNT head_refr_numb /* 참조번호 */ ,TO_CHAR(SYSDATE,'YYYYMMDD') head_docu_issu /* 문서작성일자 */
/* 주요계약정보============================================================================= */ ,'XXXXXXXXXX'||B.CONT_CNT cont_unin_numb /* 통합계약번호 */ ,'XXXXXXXXXX'||B.CONT_CNT cont_rfrn_numb /* 계약참조번호 */ ,'XXXXXXXXXX'||B.CONT_CNT cont_numb_idnr /* 확정계약번호 */ ,'00' cont_seqn_numb /* 수정차수 */ ,'N' cont_ibid_indr /* 국제입찰여부 */ ,B.CONT_DESC cont_name_text /* 계약건명 */ ,NVL( ( SELECT (CASE WHEN B.CONT_TYPE1 = 'GC' THEN '1' WHEN B.CONT_TYPE1 = 'LC' THEN '2' WHEN B.CONT_TYPE1 = 'NC' THEN '3' ELSE '4' END) CONT_TYPE1 FROM STOCBDDT K JOIN STOCBDHD B ON K.GATE_CD = B.GATE_CD AND K.BUYER_CD = B.BUYER_CD AND K.BID_NUM = B.BID_NUM AND K.BID_CNT = B.BID_CNT WHERE (K.PB_BUYER_CD,K.PR_NUM,K.PR_SQ) IN ( SELECT DISTINCT B.PB_BUYER_CD ,B.PR_NUM ,B.PR_SQ FROM STOCECCT A JOIN STOCECMT B ON A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.CONT_NUM = B.CONT_NUM AND A.CONT_CNT = B.CONT_CNT AND B.DEL_FLAG = '0' WHERE A.GATE_CD = #{ses.gateCd} AND A.BUYER_CD = #{BUYER_CD} AND A.CONT_NUM = #{CONT_NUM} AND A.CONT_CNT = #{CONT_CNT} ) AND ROWNUM = 1 ) , '1' ) cont_mean_code /* 계약방식(1:일반경쟁, 2:제한경쟁, 3:지명경쟁, 4:수의계약) */ ,'2' cont_paym_code /* 지급구분 */ ,'1' cont_clas_code /* 계약구분(1:물품, 2:외자, 3:시설, 4:비축(기타)) */ ,'F00' cont_dcls_code /* 계약상세구분 */ ,'' cont_acls_code /* 부가계약구분 */ ,CASE WHEN B.CONT_REQ_CD = '10' THEN '1' ELSE '2' END cont_ctyp_indr /* 장기계속구분 (1:신규, 2:장기, 3:계속비(신규), 4 :계속비(장기)) */ ,'' cont_rnum_idnr /* 연관계약번호 */ ,'N' cont_cprn_indr /* 공통계약여부(Y:공동, N:단독) */ ,TO_CHAR(B.CONT_DATE,'YYYYMMDD') cont_date_time /* 계약체결일자 */ ,TO_CHAR(B.CONT_START_DATE,'YYYYMMDD') cont_strt_date /* 계약시작일자 */ ,TO_CHAR(B.CONT_END_DATE,'YYYYMMDD') cont_ends_date /* 계약종료일자 */ ,B.CONT_END_DATE - B.CONT_START_DATE cont_perd_text /* 계약기간 */ ,'' cont_cmpt_date /* 이행완료일자 */ ,'01' cont_blaw_code /* 근거법률 */ ,'' cont_lcls_code /* 법률구분코드 */ ,'' cont_bcla_text /* 근거조항 */ ,'' cont_bdtl_text /* 근거내역 */ ,'' cont_acls_code /* 수의계약특례코드 */ ,'' cont_gnot_text /* 기타사항 */ --,A.PAY_AMT cont_amnt_cont /* 계약금액정보 */ ,CASE WHEN A.GUAR_TYPE = 'CONT' THEN A.PAY_AMT WHEN A.GUAR_TYPE = 'ADV' THEN A.PAY_AMT WHEN A.GUAR_TYPE = 'WARR' THEN B.CONT_AMT END cont_amnt_cont /* 계약금액정보 */ ,'' cont_this_amnt /* 금차계약금액 */ ,CASE WHEN B.AMT_TYPE = 'TA' THEN A.GUAR_PERCENT ELSE 0 END cont_amnt_rate /* 보증금율 */ ,A.GUAR_PERCENT cont_pric_rate /* 하자보증금율 */ ,ADD_MONTHS(B.CONT_END_DATE, A.GUAR_QT) - (B.CONT_END_DATE+1) cont_mrtg_perd /* 하자보수책임기간 */ ,'' cont_ntfy_info /* 공통계약여부(Y:공동, N:단독) */ ,'' cont_reqt_idnr /* 요청번호 */ ,'' cont_curl_link /* 링크URL */
/* 채권자 정보(농협정보)========================================================================= */ ,'1' coor_line_numb /* 계약기관일련번호 */ ,'2' coor_orgn_cccd /* 계약기관구분 */ ,C.IRS_NUM coor_orgn_idnr /* 기관코드 */ ,C.IRS_NUM coor_orgn_addi /* 기관부가코드 */ ,'' coor_orgn_addd /* 기관부가코드설명 */ ,C.CUST_NM coor_orgn_name /* 기관명 */ ,'' coor_orgn_gccd /* 기관분류 */ ,C.CUST_NM coor_empl_cred /* 채권자명 */ ,D.DEPT_NM coor_empl_dept /* 담당부서명 */ ,'' coor_empl_idnr /* 사용자코드 */ ,'' coor_empl_idnn /* 사용자코드설명 */ ,D.USER_NM coor_empl_name /* 담당자명 */ ,D.TEL_NUM coor_tele_numb /* 담당자전화번호 */ ,D.FAX_NUM coor_faxs_numb /* 담당자FAx번호 */
/* 계약자 정보(협력업체)===================================================================== */ ,'1' suor_line_numb /* 계약업체일련번호 */ ,'00' suor_orgn_cccd /* 계약업체구분 */ ,'' suor_orgn_ctcd /* 국적코드 */ ,E.IRS_NO suor_orgn_idnr /* 업체코드 */ ,E.IRS_NO suor_orgn_addi /* 업체부가코드 */ ,'' suor_orgn_addd /* 업체부가코드설명 */ ,E.VENDOR_NM suor_orgn_name /* 업체명 */ ,C.CUST_NM suor_orgn_cred /* 채권자명 */ ,'계약부서' suor_empl_dept /* 담당부서명 */ ,'' suor_empl_idnr /* 사용자코드 */ ,'' suor_empl_idnn /* 사용자코드설명 */ ,B.VENDOR_PIC_USER_NM suor_empl_name /* 담당자명 */ ,B.VENDOR_PIC_USER_CELL_NUM suor_tele_numb /* 담당자전화번호 */ ,'' suor_faxs_numb /* 담당자FAx번호 */ ,'' suor_ctyp_code /* 사용자코드설명 */ ,'' suor_cons_rate /* 사용자코드설명 */ ,A.GUAR_REQ_NUM ,A.INSU_STATUS ,A.GUAR_NUM FROM ( SELECT GUAR_TYPE ,GUAR_QT ,GUAR_AMT ,BOND_BEGN_DATE ,PAY_AMT ,GUAR_PERCENT ,GATE_CD ,BUYER_CD ,CONT_NUM ,CONT_CNT ,PY_BUYER_CD ,PY_DEPT_CD ,( SELECT MAX(GUAR_REQ_NUM) FROM STOCECPC WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND CONT_NUM = A.CONT_NUM AND CONT_CNT = A.CONT_CNT AND PY_BUYER_CD = A.PY_BUYER_CD AND PY_DEPT_CD = A.PY_DEPT_CD AND PAY_CNT = A.PAY_CNT ) GUAR_REQ_NUM ,INSU_STATUS ,GUAR_NUM FROM STOCECPC A WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND CONT_NUM = #{CONT_NUM} AND CONT_CNT = #{CONT_CNT} AND PR_BUYER_CD = #{PR_BUYER_CD} AND PR_DEPT_CD = #{PR_DEPT_CD} AND VENDOR_CD = #{VENDOR_CD} AND PAY_CNT = #{PAY_CNT} AND PY_BUYER_CD = #{PY_BUYER_CD} AND PY_DEPT_CD = #{PY_DEPT_CD} UNION ALL--=================================================================================== SELECT GUAR_TYPE ,GUAR_QT ,GUAR_AMT ,BOND_BEGN_DATE ,AP_REQ_AMT AS PAY_AMT ,GUAR_PERCENT ,GATE_CD ,BUYER_CD ,CONT_NUM ,CONT_CNT ,PY_BUYER_CD ,PY_DEPT_CD ,( SELECT MAX(GUAR_REQ_NUM) FROM STOCIVAP WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND CONT_NUM = A.CONT_NUM AND CONT_CNT = A.CONT_CNT AND PY_BUYER_CD = A.PY_BUYER_CD AND PY_DEPT_CD = A.PY_DEPT_CD ) GUAR_REQ_NUM ,INSU_STATUS ,GUAR_NUM FROM STOCIVAP A WHERE GATE_CD = #{ses.gateCd} AND AP_NUM = #{AP_NUM} ) A JOIN STOCECCT B ON A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.CONT_NUM = B.CONT_NUM AND A.CONT_CNT = B.CONT_CNT JOIN STOCCUST C ON A.GATE_CD = C.GATE_CD AND A.PY_BUYER_CD = C.CUST_CD JOIN STOCCVUR D ON B.GATE_CD = D.GATE_CD -- 구매사담당자 AND B.CONT_USER_ID = D.USER_ID JOIN STOCVNGL E ON B.GATE_CD = E.GATE_CD AND B.VENDOR_CD = E.VENDOR_CD LEFT OUTER JOIN ( -- 이전 계약 SELECT * FROM STOCECCT WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND CONT_NUM = #{CONT_NUM} AND CONT_CNT = #{CONT_CNT} - 1 UNION ALL SELECT * FROM STOCECCT WHERE (GATE_CD,BUYER_CD,CONT_NUM,CONT_CNT) IN ( SELECT GATE_CD,BUYER_CD,CONT_NUM,CONT_CNT - 1 FROM STOCIVAP WHERE GATE_CD = #{ses.gateCd} AND AP_NUM = #{AP_NUM} ) ) G ON 1 = 1 WHERE ROWNUM = 1

SELECT INSU_STATUS
     , GUAR_NUM
  FROM STOCECPC 
 WHERE GATE_CD = #{ses.gateCd}
   AND GUAR_NUM = #{GUAR_NUM} 
   AND GUAR_TYPE =  #{GUAR_TYPE}

SELECT BUYER_CD
	 , CONT_NUM
	 , CONT_CNT
	 , PR_BUYER_CD
	 , PR_DEPT_CD
	 , VENDOR_CD
	 , PDF_ATT_FILE_NUM
  FROM STOCECCM
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND VENDOR_CD = #{VENDOR_CD}

mapper.insert:
        MERGE  STOCBDAP BDAP
        USING (SELECT
                     #{ses.gateCd} AS GATE_CD
                    ,#{BUYER_CD}   AS BUYER_CD
                    ,#{BID_NUM}    AS BID_NUM
                    ,#{BID_CNT}    AS BID_CNT
                    ,#{VENDOR_CD}  AS VENDOR_CD
                ) B
	         ON (BDAP.GATE_CD   = B.GATE_CD
	         AND BDAP.BUYER_CD  = B.BUYER_CD
	         AND BDAP.BID_NUM   = B.BID_NUM
	         AND BDAP.BID_CNT   = B.BID_CNT
	         AND BDAP.VENDOR_CD = B.VENDOR_CD)
        WHEN MATCHED THEN
        UPDATE SET
             MOD_DATE = SYSDATE
            ,MOD_USER_ID = #{ses.userId}
            ,BID_GUAR_AMT = #{BID_GUAR_AMT}
            ,BID_GUAR_TYPE = #{BID_GUAR_TYPE}
            ,GUARANTEER = #{GUARANTEER}
            ,GUAR_REQ_NUM = #{GUAR_REQ_NUM}
            ,GUAR_NUM = #{GUAR_NUM}
            ,INSU_STATUS = 'TA'
        WHEN NOT MATCHED THEN
        INSERT (
             GATE_CD
            ,BUYER_CD
            ,BID_NUM
            ,BID_CNT
            ,VENDOR_CD
            ,REG_DATE
            ,REG_USER_ID
            ,MOD_DATE
            ,MOD_USER_ID
            ,DEL_FLAG
            ,BID_GUAR_AMT
            ,BID_GUAR_TYPE
            ,GUARANTEER
            ,GUAR_REQ_NUM
            ,GUAR_NUM
            ,GUAR_ATT_FILE_NUM
            ,INSU_STATUS
        ) VALUES (
             #{ses.gateCd}
            ,#{BUYER_CD}
            ,#{BID_NUM}
            ,#{BID_CNT}
            ,#{VENDOR_CD}
            ,SYSDATE
            ,#{ses.userId}
            ,SYSDATE
            ,#{ses.userId}
            ,'0'
            ,#{BID_GUAR_AMT}
            ,#{BID_GUAR_TYPE}
            ,#{GUARANTEER}
            ,#{GUAR_REQ_NUM}
            ,#{GUAR_NUM}
            ,#{GUAR_ATT_FILE_NUM}
            ,'TA'
        )

mapper.update:
	UPDATE STOCBDAP 
	   SET GUAR_REQ_NUM       = NULL
	     , GUAR_NUM 		  = NULL
    	 , GUAR_RESULT    	  = NULL
    	 , INSU_STATUS	      = NULL
		 , GUARANTEER     	  = NULL
		 , BID_GUAR_TYPE      = NULL
		 , BID_GUAR_AMT       = NULL
	WHERE GUAR_REQ_NUM  = #{GUAR_REQ_NUM}
	  AND BID_NUM       = #{BID_NUM}
	  AND BID_CNT       = #{BID_CNT}
	  AND VENDOR_CD     = #{VENDOR_CD}
	  AND BID_GUAR_TYPE = #{BID_GUAR_TYPE}

