SELECT GETCOMCODE(ECPC.GATE_CD, 'M404', ECPC.GUAR_TYPE, 0, #{ses.langCd}) AS GUAR_TYPE , GETBUYERDEPTNAME(ECPC.GATE_CD, ECPC.PR_BUYER_CD, ECPC.PR_DEPT_CD, #{ses.langCd}) AS PR_BUYER_DEPT_NM , ECPC.GUAR_NUM , (SELECT CONT_DESC FROM STOCECCT WHERE GATE_CD = ECPC.GATE_CD AND BUYER_CD = ECPC.BUYER_CD AND CONT_NUM = ECPC.CONT_NUM AND CONT_CNT = ECPC.CONT_CNT AND VENDOR_CD = ECPC.VENDOR_CD AND DEL_FLAG = '0') AS CONT_DESC , (SELECT CONT_NUM FROM STOCECCT WHERE GATE_CD = ECPC.GATE_CD AND BUYER_CD = ECPC.BUYER_CD AND CONT_NUM = ECPC.CONT_NUM AND CONT_CNT = ECPC.CONT_CNT AND VENDOR_CD = ECPC.VENDOR_CD AND DEL_FLAG = '0') AS CONT_NUM , (SELECT CONT_USER_ID FROM STOCECCT WHERE GATE_CD = ECPC.GATE_CD AND BUYER_CD = ECPC.BUYER_CD AND CONT_NUM = ECPC.CONT_NUM AND CONT_CNT = ECPC.CONT_CNT AND DEL_FLAG = '0') AS CONT_USER_ID , (SELECT GETUSERNAME(GATE_CD, CONT_USER_ID, #{ses.langCd}) FROM STOCECCT WHERE GATE_CD = ECPC.GATE_CD AND BUYER_CD = ECPC.BUYER_CD AND CONT_NUM = ECPC.CONT_NUM AND CONT_CNT = ECPC.CONT_CNT AND DEL_FLAG = '0') AS CONT_USER_NM , ECPC.VENDOR_CD , GETVENDORNAME(ECPC.GATE_CD, ECPC.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , (SYSDATE, 'YYYY-MM-DD') AS SYS_DATE FROM STOCECPC ECPC WHERE ECPC.GATE_CD = #{ses.gateCd} AND ECPC.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd}) AND ECPC.CONT_NUM = #{CONT_NUM} AND ECPC.CONT_CNT = #{CONT_CNT} AND ECPC.PY_BUYER_CD = #{PR_BUYER_CD} AND ECPC.PY_DEPT_CD = #{PR_DEPT_CD} AND ECPC.VENDOR_CD = #{VENDOR_CD}
AND ECPC.PAY_CNT = #{PAY_CNT}
AND ECPC.GUAR_TYPE = #{GUAR_TYPE} AND ECPC.GUAR_PERCENT > 0 AND ECPC.GUAR_TYPE2 IS NOT NULL AND ECPC.DEL_FLAG = '0'

