    ,GUAR_RESULT = #{GUAR_RESULT}
    ,INSU_STATUS = #{INSU_STATUS}
	WHERE GUAR_REQ_NUM = #{GUAR_REQ_NUM}
	AND GUAR_TYPE = #{GUAR_TYPE}

mapper.insert:
		MERGE  GRTSWGUA  A
        USING (SELECT #{BOND_NUMB_TEXT} AS GUARANTEE_SEQ
                 ) B
            ON (A.GUARANTEE_SEQ = B.GUARANTEE_SEQ)
        WHEN MATCHED THEN
        UPDATE SET
              HEAD_MESG_SEND = #{HEAD_MESG_SEND}
			, HEAD_MESG_RECV = #{HEAD_MESG_RECV}
			, HEAD_FUNC_CODE = #{HEAD_FUNC_CODE}
			, HEAD_MESG_TYPE = #{HEAD_MESG_TYPE}
			, HEAD_MESG_NAME = #{HEAD_MESG_NAME}
			, HEAD_MESG_VERS = #{HEAD_MESG_VERS}
			, HEAD_DOCU_NUMB = #{HEAD_DOCU_NUMB}
			, HEAD_MANG_NUMB = #{HEAD_MANG_NUMB}
			, HEAD_REFR_NUMB = #{HEAD_REFR_NUMB}
			, HEAD_TITL_NAME = #{HEAD_TITL_NAME}
			, HEAD_ORGA_CODE = #{HEAD_ORGA_CODE}
			, BOND_ORGA_NAME = #{BOND_ORGA_NAME}
			, BOND_ORGA_IDEN = #{BOND_ORGA_IDEN}
			, BOND_ORGA_ADDN = #{BOND_ORGA_ADDN}
			, BOND_ORGA_CEO  = #{BOND_ORGA_CEO}
			, GOVN_ORGA_NAME = #{GOVN_ORGA_NAME}
			, GOVN_ORGA_IDEN = #{GOVN_ORGA_IDEN}
			, GOVN_ORGA_ADDN = #{GOVN_ORGA_ADDN} 
			, GOVN_OWNR_NAME = #{GOVN_OWNR_NAME}
			, DOCU_ISSU_DATE = #{DOCU_ISSU_DATE}
			, BUSI_CLAS_CODE = #{BUSI_CLAS_CODE}
			, BOND_NUMB_TEXT = #{BOND_NUMB_TEXT}
