SELECT '004'|| CASE WHEN A.GUAR_TYPE = 'ADV' THEN '004' WHEN A.GUAR_TYPE = 'CONT' THEN '002' WHEN A.GUAR_TYPE = 'WARR' THEN '003' END||'XXXXXXXXXX'||' 00' head_docu_numb
,#{HEAD_MESG_SEND}||'.'||TO_CHAR(SYSDATE,'YYYYMMDD')||TO_CHAR(SYSDATE,'HH24MISS')||'.12345.004'|| CASE WHEN A.GUAR_TYPE = 'ADV' THEN '004' WHEN A.GUAR_TYPE = 'CONT' THEN '002' WHEN A.GUAR_TYPE = 'WARR' THEN '003' END||'XXXXXXXXXX'||' 00' head_mang_numb
,'004'|| CASE WHEN A.GUAR_TYPE = 'ADV' THEN '004' WHEN A.GUAR_TYPE = 'CONT' THEN '002' WHEN A.GUAR_TYPE = 'WARR' THEN '003' END||'XXXXXXXXXX'||' 00' head_refr_numb
/* 문서정보 ===================================================================== */ ,'XXXXXXXXXX'||' 00' docu_numb_text ,CASE WHEN A.GUAR_TYPE = 'ADV' THEN '004' WHEN A.GUAR_TYPE = 'CONT' THEN '002' WHEN A.GUAR_TYPE = 'WARR' THEN '003' END docu_kind_code /* [필수] " 보험종목구분(002:계약,003:하자,004:선금,006:지급)" */ , null docu_issu_date /* [선택] 작성일자 */ , null docu_user_type /* [필수] 발신처TYPE */
/* 주요계약정보===================================================================== */ ,'XXXXXXXXXX' cont_numb_text /* [필수] 계약번호 */ ,B.CONT_DESC cont_main_name /* [필수] 계약건명 */ ,'WON' cont_curc_code /* [선택] 계약금액(원화)/통화코드(WON) */ ,B.CONT_AMT cont_main_amnt /* [선택] 계약금액(원화)/계약금액 */
/* 채권자 정보(구매사)===================================================================== */ ,C.CUST_NM cred_bond_hold /* [필수] 채권자명 */
/* 계약자 정보(협력업체)===================================================================== */ ,E.VENDOR_NM appl_orga_name /* [필수] 기관명 */ ,'O' appl_orps_divs /* [필수] 구분(O:사업자번호 P:주민등록번호) */ ,E.IRS_NO appl_orps_iden /* [필수] 사업자/주민번호 */ ,E.CEO_USER_NM appl_ownr_name /* [필수] 성명(대표자명) */ ,A.GUAR_REQ_NUM ,A.INSU_STATUS ,(SUBSTR(A.GUAR_NUM, 7, 18), '') AS GUAR_NUM FROM ( SELECT GUAR_TYPE ,GUAR_QT ,GUAR_AMT ,BOND_BEGN_DATE ,PAY_AMT ,GUAR_PERCENT ,GATE_CD ,BUYER_CD ,CONT_NUM ,CONT_CNT ,PY_BUYER_CD ,PY_DEPT_CD ,( SELECT MAX(GUAR_REQ_NUM) FROM STOCECPC WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND CONT_NUM = A.CONT_NUM AND CONT_CNT = A.CONT_CNT AND PY_BUYER_CD = A.PY_BUYER_CD AND PY_DEPT_CD = A.PY_DEPT_CD AND PAY_CNT = A.PAY_CNT ) GUAR_REQ_NUM ,INSU_STATUS ,GUAR_NUM FROM STOCECPC A WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND CONT_NUM = #{CONT_NUM} AND CONT_CNT = #{CONT_CNT} AND PR_BUYER_CD = #{PR_BUYER_CD} AND PR_DEPT_CD = #{PR_DEPT_CD} AND VENDOR_CD = #{VENDOR_CD} AND PAY_CNT = #{PAY_CNT} AND PY_BUYER_CD = #{PY_BUYER_CD} AND PY_DEPT_CD = #{PY_DEPT_CD} UNION ALL--=================================================================================== SELECT GUAR_TYPE ,GUAR_QT ,GUAR_AMT ,BOND_BEGN_DATE ,AP_REQ_AMT AS PAY_AMT ,GUAR_PERCENT ,GATE_CD ,BUYER_CD ,CONT_NUM ,CONT_CNT ,PY_BUYER_CD ,PY_DEPT_CD ,( SELECT MAX(GUAR_REQ_NUM) FROM STOCIVAP WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND CONT_NUM = A.CONT_NUM --AND CONT_CNT = A.CONT_CNT --AND PY_BUYER_CD = A.PY_BUYER_CD --AND PY_DEPT_CD = A.PY_DEPT_CD ) GUAR_REQ_NUM ,INSU_STATUS ,GUAR_NUM FROM STOCIVAP A WHERE GATE_CD = #{ses.gateCd} AND AP_NUM = #{AP_NUM} ) A JOIN STOCECCT B ON A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.CONT_NUM = B.CONT_NUM AND A.CONT_CNT = B.CONT_CNT JOIN STOCCUST C ON A.GATE_CD = C.GATE_CD AND A.PY_BUYER_CD = C.CUST_CD JOIN STOCCVUR D ON B.GATE_CD = D.GATE_CD -- 구매사담당자 AND B.CONT_USER_ID = D.USER_ID JOIN STOCVNGL E ON B.GATE_CD = E.GATE_CD AND B.VENDOR_CD = E.VENDOR_CD LEFT OUTER JOIN ( -- 이전 계약 SELECT * FROM STOCECCT WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND CONT_NUM = #{CONT_NUM} AND CONT_CNT = #{CONT_CNT} - 1 UNION ALL SELECT * FROM STOCECCT WHERE (GATE_CD,BUYER_CD,CONT_NUM,CONT_CNT) IN ( SELECT GATE_CD,BUYER_CD,CONT_NUM,CONT_CNT - 1 FROM STOCIVAP WHERE GATE_CD = #{ses.gateCd} AND AP_NUM = #{AP_NUM} ) ) G ON 1 = 1 WHERE ROWNUM = 1

SELECT A.* FROM ( SELECT GETCOMCODE(ECPC.GATE_CD, 'M404', ECPC.GUAR_TYPE, 0, #{ses.langCd}) AS GUAR_TYPE , (SELECT CONT_DESC FROM STOCECCT WHERE GATE_CD = ECPC.GATE_CD AND BUYER_CD = ECPC.BUYER_CD AND CONT_NUM = ECPC.CONT_NUM AND CONT_CNT = ECPC.CONT_CNT AND VENDOR_CD = ECPC.VENDOR_CD AND DEL_FLAG = '0') AS CONT_DESC , ECPC.VENDOR_CD , GETVENDORNAME(ECPC.GATE_CD, ECPC.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , CVUR.USER_ID , CVUR.USER_NM AS USER_NM , (SYSDATE, 'YYYY-MM-DD') AS SYS_DATE FROM STOCECPC ECPC JOIN STOCCVUR CVUR ON (CVUR.GATE_CD = ECPC.GATE_CD AND CVUR.COMPANY_CD = ECPC.VENDOR_CD AND CVUR.BLOCK_FLAG = '0' AND CVUR.MAIL_FLAG = '1' AND CVUR.EMAIL IS NOT NULL AND CVUR.DEL_FLAG = '0') WHERE ECPC.GATE_CD = #{ses.gateCd} AND ECPC.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd}) AND ECPC.CONT_NUM = #{CONT_NUM} AND ECPC.CONT_CNT = #{CONT_CNT} AND ECPC.PR_BUYER_CD = #{PR_BUYER_CD} AND ECPC.PR_DEPT_CD = #{PR_DEPT_CD} AND ECPC.VENDOR_CD = #{VENDOR_CD}
AND ECPC.PAY_CNT = #{PAY_CNT}
AND ECPC.GUAR_TYPE = #{GUAR_TYPE} AND ECPC.GUAR_PERCENT > 0 AND ECPC.DEL_FLAG = '0' ORDER BY CVUR.MNG_YN DESC ) A WHERE ROWNUM <= 2

