UPDATE STOCECPC
   SET GUAR_TYPE2     	  = #{GUAR_TYPE2}
	 , GUARANTEER     	  = #{GUARANTEER}
	 , ATT_FILE_NUM       = #{ATT_FILE_NUM}
WHERE GATE_CD    = #{ses.gateCd}
AND BUYER_CD     = #{BUYER_CD}
AND CONT_NUM     = #{CONT_NUM}
AND CONT_CNT     = #{CONT_CNT}
AND PR_BUYER_CD  = #{PR_BUYER_CD}
AND PR_DEPT_CD   = #{PR_DEPT_CD}
AND VENDOR_CD    = #{VENDOR_CD}
AND PAY_CNT      = #{PAY_CNT}
AND PY_BUYER_CD  = #{PY_BUYER_CD}
AND PY_DEPT_CD   = #{PY_DEPT_CD}


INSERT INTO STOCDFSV (
	  GATE_CD
	, VENDOR_CD
	, UUID
	, UUID_SQ
	, SEQ
	, SIGN_ID
	, REG_DATE
	, REG_USER_ID
	, SIGN_DATE
	, SIGN_VALUE
	, VID_RANDOM
) VALUES (
	  #{ses.gateCd}
	, #{VENDOR_CD}
	, #{UUID}
	, #{UUID_SQ}
	,(SELECT (MAX(SEQ)+1, '1')
	    FROM STOCDFSV
	   WHERE GATE_CD = #{ses.gateCd}
	     AND VENDOR_CD = #{VENDOR_CD}
	     AND UUID = #{UUID}
	     AND UUID_SQ = #{UUID_SQ})			
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{SIGN_VALUE}
	, #{VID_RANDOM}
)
